import { useState } from "react";

export default function SimpleForm() {
  const [value, setValue] = useState("");

  function handleEvent(e) {
    e.preventDefault();
    alert("Дані успішно відправлено", value);
    setValue("");
  }

  return (
    <form onSubmit={handleEvent}>
      <input type="text" />
    </form>
  );
}
